function HomeScreen({ budgets, setBudgets, onSelect }) {
  const [mode, setMode]         = useState("list"); // list | add | edit
  const [editingId, setEditingId] = useState(null);

  const addBudget = (form) => {
    const b = {
      id: Date.now(),
      name: form.name.trim(),
      className: form.className.trim(),
      year: form.year.trim(),
      colorKey: form.colorKey,
      feePerStudent: Number(form.feePerStudent) || 500,
      expectedStudents: 0,
      students: [], events: [], cashLog: [], gifts: [],
    };
    setBudgets(prev => [...prev, b]);
    setMode("list");
  };

  const saveBudget = (form) => {
    setBudgets(prev => prev.map(b => b.id === editingId
      ? { ...b, name: form.name.trim(), className: form.className.trim(), year: form.year.trim(), colorKey: form.colorKey, feePerStudent: Number(form.feePerStudent) || b.feePerStudent }
      : b
    ));
    setMode("list"); setEditingId(null);
  };

  const deleteBudget = (id) => {
    if (window.confirm("למחוק תקציב זה? הנתונים יאבדו לצמיתות.")) {
      setBudgets(prev => prev.filter(b => b.id !== id));
    }
  };

  const editingBudget = budgets.find(b => b.id === editingId);

  return (
    <div style={{ minHeight: "100vh", background: "#f8fafc" }}>
      {/* Header */}
      <div style={{
        background: "linear-gradient(135deg, #1e293b 0%, #0f172a 100%)",
        padding: "24px 20px 28px",
      }}>
        <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 12, fontWeight: 600, letterSpacing: 1, textTransform: "uppercase", marginBottom: 6 }}>מנהל תקציבים</div>
        <div style={{ color: "white", fontWeight: 900, fontSize: 24 }}>ועד הורים 🏫</div>
        <div style={{ color: "rgba(255,255,255,0.6)", fontSize: 13, marginTop: 4 }}>בחרי תקציב לניהול</div>
      </div>

      <div style={{ padding: "20px 14px 30px" }}>
        {mode === "add" && (
          <BudgetForm title="➕ תקציב חדש" onSave={addBudget} onCancel={() => setMode("list")} />
        )}
        {mode === "edit" && editingBudget && (
          <BudgetForm
            title="✏️ עריכת תקציב"
            initial={{ ...editingBudget, feePerStudent: String(editingBudget.feePerStudent) }}
            onSave={saveBudget}
            onCancel={() => { setMode("list"); setEditingId(null); }}
          />
        )}

        {budgets.length === 0 && mode === "list" && (
          <div style={{ textAlign: "center", color: "#94a3b8", padding: "40px 0" }}>
            <div style={{ fontSize: 40, marginBottom: 12 }}>📋</div>
            <div style={{ fontSize: 15, fontWeight: 600 }}>אין תקציבים עדיין</div>
            <div style={{ fontSize: 13, marginTop: 4 }}>לחצי על הכפתור למטה כדי להוסיף</div>
          </div>
        )}

        {mode === "list" && budgets.map(b => (
          <BudgetListCard
            key={b.id}
            budget={b}
            onSelect={() => onSelect(b.id)}
            onEdit={() => { setEditingId(b.id); setMode("edit"); }}
            onDelete={() => deleteBudget(b.id)}
          />
        ))}

        {mode === "list" && (
          <button onClick={() => setMode("add")} style={{
            width: "100%", padding: 16, borderRadius: 16, border: "2px dashed #cbd5e1",
            background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
            cursor: "pointer", fontFamily: "inherit",
          }}>+ הוסיפי תקציב חדש</button>
        )}
      </div>
    </div>
  );
}

