// ─────────────────────────────────────────
const EMPTY_EVENT = { name: "", date: "", budget: "", spent: "", category: "פעילות", notes: "", paidBy: "", done: false, type: "expense" };

function EventForm({ data, onChange, onSave, onCancel, title }) {
  return (
    <Card style={{ border: "2px solid #ede9fe" }}>
      <div style={{ fontWeight: 700, marginBottom: 10, fontSize: 14 }}>{title}</div>
      <div style={{ display: "flex", gap: 8, marginBottom: 10 }}>
        {["expense", "income"].map(t => (
          <button key={t} onClick={() => onChange({ ...data, type: t })} style={{
            flex: 1, padding: "10px 0", borderRadius: 10, border: "none",
            cursor: "pointer", fontFamily: "inherit", fontWeight: 700, fontSize: 13,
            background: data.type === t ? (t === "expense" ? "#fee2e2" : "#dcfce7") : "#f1f5f9",
            color:      data.type === t ? (t === "expense" ? "#ef4444" : "#059669") : "#94a3b8",
          }}>{t === "expense" ? "📤 הוצאה" : "📥 הכנסה"}</button>
        ))}
      </div>
      <FieldLabel>שם הארוע *</FieldLabel>
      <input value={data.name} onChange={e => onChange({ ...data, name: e.target.value })} placeholder="שם הארוע" style={S.input} autoFocus />
      <FieldLabel>תאריך</FieldLabel>
      <input value={data.date} onChange={e => onChange({ ...data, date: e.target.value })} placeholder="תאריך" style={S.input} />
      <div style={{ display: "flex", gap: 8 }}>
        <div style={{ flex: 1 }}>
          <FieldLabel>תקציב ₪</FieldLabel>
          <input type="number" value={data.budget} onChange={e => onChange({ ...data, budget: e.target.value })} placeholder="0" style={S.input} />
        </div>
        <div style={{ flex: 1 }}>
          <FieldLabel>{(data.type || "expense") === "income" ? "התקבל ₪" : "שולם ₪"}</FieldLabel>
          <input type="number" value={data.spent} onChange={e => onChange({ ...data, spent: e.target.value })} placeholder="0" style={S.input} />
        </div>
      </div>
      <FieldLabel>קטגוריה</FieldLabel>
      <select value={data.category} onChange={e => onChange({ ...data, category: e.target.value })} style={S.input}>
        {CAT_LIST.map(c => <option key={c}>{c}</option>)}
      </select>
      <FieldLabel>הערות</FieldLabel>
      <input value={data.notes} onChange={e => onChange({ ...data, notes: e.target.value })} placeholder="הערות" style={S.input} />
      <FieldLabel>{(data.type || "expense") === "income" ? "נגבה ע״י" : "שולם ע״י"}</FieldLabel>
      <input value={data.paidBy || ""} onChange={e => onChange({ ...data, paidBy: e.target.value })} placeholder={(data.type || "expense") === "income" ? "מי גבה" : "שולם ע״י"} style={S.input} />
      <label style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12, cursor: "pointer", fontSize: 13 }}>
        <input type="checkbox" checked={!!data.done} onChange={e => onChange({ ...data, done: e.target.checked })} style={{ width: 16, height: 16 }} />
        הושלם ✅
      </label>
      <div style={{ display: "flex", gap: 8 }}>
        <button onClick={onSave} style={S.btn("#7c3aed")} disabled={!data.name.trim()}>שמור</button>
        <button onClick={onCancel} style={S.btn("#94a3b8")}>ביטול</button>
      </div>
    </Card>
  );
}

function BudgetTab({ events, setEvents, collectionBudget = 0 }) {
  const [showAdd, setShowAdd] = useState(false);
  const [filter, setFilter]  = useState("הכל");
  const [addForm, setAddForm] = useState(EMPTY_EVENT);
  const [editId, setEditId]  = useState(null);
  const [editForm, setEditForm] = useState({});

  const totalExpBudget = events.filter(e => (e.type || "expense") === "expense").reduce((s, e) => s + e.budget, 0);
  const totalIncBudget = collectionBudget + events.filter(e => (e.type || "expense") === "income").reduce((s, e) => s + e.budget, 0);
  const totalSpent     = events.filter(e => (e.type || "expense") === "expense").reduce((s, e) => s + e.spent, 0);
  const cats           = ["הכל", ...CAT_LIST];
  const filtered       = filter === "הכל" ? events : events.filter(e => e.category === filter);
  const parseSortDate  = (d) => { const m = d && d.match(/^(\d{1,2})\.(\d{1,2})\.(\d{2,4})$/); if (m) { let y = parseInt(m[3]); if (y < 100) y += 2000; return new Date(y, parseInt(m[2]) - 1, parseInt(m[1])).getTime(); } return Infinity; };
  const sorted         = [...filtered].sort((a, b) => parseSortDate(a.date) - parseSortDate(b.date));

  const addEvent = () => {
    if (!addForm.name.trim()) return;
    setEvents([...events, { id: Date.now(), ...addForm, budget: Number(addForm.budget) || 0, spent: Number(addForm.spent) || 0 }]);
    setAddForm(EMPTY_EVENT); setShowAdd(false);
  };

  const startEdit  = (ev) => { setEditId(ev.id); setEditForm({ ...ev, budget: String(ev.budget), spent: String(ev.spent), type: ev.type || "expense" }); };
  const cancelEdit = () => setEditId(null);
  const saveEdit   = () => {
    setEvents(events.map(e => e.id === editId ? { ...editForm, id: editId, budget: Number(editForm.budget) || 0, spent: Number(editForm.spent) || 0 } : e));
    setEditId(null);
  };
  const removeEvent = (id) => { if (window.confirm("למחוק ארוע זה?")) setEvents(events.filter(e => e.id !== id)); };
  const toggleDone  = (id) => setEvents(events.map(e => e.id === id ? { ...e, done: !e.done } : e));

  return (
    <div>
      {/* Summary */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 16 }}>
        {[
          { l: "תקציב הוצאות", v: `₪${totalExpBudget.toLocaleString()}`, c: "#ef4444", icon: "📤" },
          { l: "תקציב הכנסות", v: `₪${totalIncBudget.toLocaleString()}`, c: "#059669", icon: "📥" },
          { l: "שולם בפועל",   v: `₪${totalSpent.toLocaleString()}`,     c: "#db2777", icon: "💸" },
          { l: "יתרה תקציבית", v: `₪${(totalIncBudget - totalExpBudget).toLocaleString()}`, c: totalIncBudget >= totalExpBudget ? "#7c3aed" : "#ef4444", icon: "💰" },
        ].map(x => (
          <div key={x.l} style={{ background: "white", borderRadius: 14, padding: "12px 8px", textAlign: "center", boxShadow: "0 2px 10px rgba(0,0,0,0.07)" }}>
            <div style={{ fontSize: 18 }}>{x.icon}</div>
            <div style={{ fontWeight: 900, fontSize: 15, color: x.c }}>{x.v}</div>
            <div style={{ fontSize: 10, color: "#94a3b8" }}>{x.l}</div>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div style={{ display: "flex", gap: 6, overflowX: "auto", marginBottom: 14, paddingBottom: 2 }}>
        {cats.map(c => (
          <button key={c} onClick={() => setFilter(c)} style={{
            padding: "6px 12px", borderRadius: 20, border: "none", cursor: "pointer",
            fontFamily: "inherit", fontWeight: 600, fontSize: 12, whiteSpace: "nowrap",
            background: filter === c ? "#7c3aed" : "#f1f5f9",
            color:      filter === c ? "white"   : "#64748b",
          }}>{c}</button>
        ))}
      </div>

      {/* Event list */}
      {sorted.map(ev => {
        const isIncome = (ev.type || "expense") === "income";
        return editId === ev.id ? (
          <EventForm key={ev.id} title="✏️ עריכת ארוע" data={editForm} onChange={setEditForm} onSave={saveEdit} onCancel={cancelEdit} />
        ) : (
          <Card key={ev.id} style={{ opacity: ev.done ? 0.65 : 1, padding: "12px 14px", borderRight: `3px solid ${isIncome ? "#22c55e" : "#7c3aed"}` }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 4, flexWrap: "wrap" }}>
                  <button onClick={() => toggleDone(ev.id)} style={{ background: "none", border: "none", cursor: "pointer", fontSize: 16, padding: 0, lineHeight: 1 }}>
                    {ev.done ? "✅" : "⬜"}
                  </button>
                  <span style={{ fontWeight: 700, fontSize: 14, color: "#0f172a" }}>{ev.name}</span>
                  <span style={{ fontSize: 10, fontWeight: 700, padding: "1px 6px", borderRadius: 8, background: isIncome ? "#dcfce7" : "#fee2e2", color: isIncome ? "#059669" : "#ef4444" }}>
                    {isIncome ? "📥 הכנסה" : "📤 הוצאה"}
                  </span>
                </div>
                <div style={{ display: "flex", gap: 6, alignItems: "center", marginBottom: 4, flexWrap: "wrap" }}>
                  <Badge text={ev.category} cat={ev.category} />
                  <span style={{ fontSize: 11, color: "#94a3b8" }}>{ev.date}</span>
                  {ev.paidBy && <span style={{ fontSize: 11, color: "#64748b" }}>👤 {ev.paidBy}</span>}
                </div>
                {ev.notes && <div style={{ fontSize: 11, color: "#64748b" }}>📝 {ev.notes}</div>}
              </div>
              <div style={{ textAlign: "left", flexShrink: 0, marginRight: 8 }}>
                <div style={{ fontWeight: 900, fontSize: 16, color: "#0f172a" }}>₪{ev.budget.toLocaleString()}</div>
                <div style={{ fontSize: 10, color: "#94a3b8" }}>תקציב</div>
                {ev.spent > 0 && <div style={{ fontSize: 12, fontWeight: 700, color: isIncome ? "#059669" : "#db2777", marginTop: 2 }}>₪{ev.spent.toLocaleString()} {isIncome ? "התקבל" : "שולם"}</div>}
              </div>
            </div>
            {ev.spent > 0 && ev.budget > 0 && (
              <ProgressBar
                pct={(ev.spent / ev.budget) * 100}
                color={isIncome ? "#22c55e" : ((ev.spent / ev.budget) > 1 ? "#ef4444" : (ev.spent / ev.budget) > 0.8 ? "#f59e0b" : "#7c3aed")}
                style={{ marginTop: 8, marginBottom: 4 }}
              />
            )}
            <div style={{ display: "flex", gap: 6, marginTop: 8 }}>
              <button onClick={() => startEdit(ev)} style={S.smallBtn("#e2e8f0", "#64748b")}>✏️ ערכי</button>
              <button onClick={() => removeEvent(ev.id)} style={S.smallBtn("#fee2e2", "#ef4444")}>✕ מחקי</button>
            </div>
          </Card>
        );
      })}

      {/* Add form */}
      {showAdd ? (
        <EventForm title="➕ ארוע חדש" data={addForm} onChange={setAddForm} onSave={addEvent} onCancel={() => setShowAdd(false)} />
      ) : (
        <button onClick={() => setShowAdd(true)} style={{
          width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
          background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
          cursor: "pointer", fontFamily: "inherit",
        }}>+ הוסיפי ארוע</button>
      )}
    </div>
  );
}

// ─────────────────────────────────────────
// COLLECT TAB — Students with edit
// ─────────────────────────────────────────
function CollectTab({ students, setStudents, feePerStudent = 500, setFeePerStudent, expectedStudents = 0, setExpectedStudents }) {
  const [search,   setSearch]   = useState("");
  const [showAdd,  setShowAdd]  = useState(false);
  const [newName,  setNewName]  = useState("");
  const [editId,   setEditId]   = useState(null);
  const [editForm, setEditForm] = useState({});

  const paidCount      = students.filter(s => s.paid).length;
  const totalCollected = students.reduce((s, st) => s + (st.amount || 0), 0);
  const collectionBudgetTotal = expectedStudents * feePerStudent;
  const filtered       = search ? students.filter(s => s.name.includes(search)) : students;

  const toggle = (id) => setStudents(students.map(s =>
    s.id === id ? { ...s, paid: !s.paid, amount: !s.paid ? feePerStudent : s.amount } : s
  ));

  const addStudent = () => {
    if (!newName.trim()) return;
    setStudents([...students, { id: Date.now(), name: newName.trim(), paid: false, amount: 0, note: "" }]);
    setNewName(""); setShowAdd(false);
  };

  const startEdit = (s) => { setEditId(s.id); setEditForm({ ...s, amount: String(s.amount) }); };
  const cancelEdit = () => setEditId(null);
  const saveEdit = () => {
    setStudents(students.map(s => s.id === editId
      ? { ...editForm, id: editId, amount: Number(editForm.amount) || 0, paid: !!editForm.paid }
      : s
    ));
    setEditId(null);
  };
  const removeStudent = (id) => { if (window.confirm("למחוק תלמיד זה?")) setStudents(students.filter(s => s.id !== id)); };

  return (
    <div>
      {/* Collection budget settings */}
      <Card style={{ marginBottom: 12 }}>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
          <div>
            <FieldLabel>מספר תלמידים</FieldLabel>
            <input type="number" value={expectedStudents} onChange={e => setExpectedStudents && setExpectedStudents(Number(e.target.value) || 0)} style={{ ...S.input, marginBottom: 0 }} />
          </div>
          <div>
            <FieldLabel>סכום לגבייה ₪</FieldLabel>
            <input type="number" value={feePerStudent} onChange={e => setFeePerStudent && setFeePerStudent(Number(e.target.value) || 0)} style={{ ...S.input, marginBottom: 0 }} />
          </div>
        </div>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 10, padding: "8px 12px", background: "#f0fdf4", borderRadius: 10 }}>
          <span style={{ fontSize: 13, fontWeight: 700, color: "#166534" }}>תקציב גבייה</span>
          <span style={{ fontSize: 17, fontWeight: 900, color: "#059669" }}>₪{collectionBudgetTotal.toLocaleString()}</span>
        </div>
      </Card>

      {/* Stats */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 16 }}>
        {[
          { l: "שילמו",    v: paidCount,                            c: "#059669", icon: "✅" },
          { l: "לא שילמו", v: students.length - paidCount,          c: "#ef4444", icon: "❌" },
          { l: "נגבה",     v: `₪${totalCollected.toLocaleString()}`, c: "#7c3aed", icon: "💰" },
        ].map(x => (
          <div key={x.l} style={{ background: "white", borderRadius: 14, padding: "12px 8px", textAlign: "center", boxShadow: "0 2px 10px rgba(0,0,0,0.07)" }}>
            <div style={{ fontSize: 18 }}>{x.icon}</div>
            <div style={{ fontWeight: 900, fontSize: 18, color: x.c }}>{x.v}</div>
            <div style={{ fontSize: 10, color: "#94a3b8" }}>{x.l}</div>
          </div>
        ))}
      </div>

      <input placeholder="🔍 חפשי תלמיד..." value={search}
        onChange={e => setSearch(e.target.value)} style={{ ...S.input, marginBottom: 10 }} />

      {students.length > 0 && (
        <>
          <ProgressBar pct={(paidCount / students.length) * 100} color="linear-gradient(90deg,#059669,#7c3aed)" />
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: "#94a3b8", marginBottom: 14, marginTop: 4 }}>
            <span>0%</span>
            <span style={{ fontWeight: 600 }}>{Math.round((paidCount / students.length) * 100)}% שולם</span>
            <span>100%</span>
          </div>
        </>
      )}

      {filtered.map(s => (
        editId === s.id ? (
          <Card key={s.id} style={{ border: "2px solid #ede9fe" }}>
            <div style={{ fontWeight: 700, marginBottom: 10, fontSize: 14 }}>✏️ עריכת תלמיד</div>
            <FieldLabel>שם</FieldLabel>
            <input value={editForm.name} onChange={e => setEditForm({ ...editForm, name: e.target.value })} style={S.input} autoFocus />
            <FieldLabel>סכום ששולם ₪</FieldLabel>
            <input type="number" value={editForm.amount} onChange={e => setEditForm({ ...editForm, amount: e.target.value })} style={S.input} />
            <FieldLabel>הערה</FieldLabel>
            <input value={editForm.note || ""} onChange={e => setEditForm({ ...editForm, note: e.target.value })} placeholder="הערה..." style={S.input} />
            <FieldLabel>שולם / נגבה ע״י (אופציונלי)</FieldLabel>
            <input value={editForm.paidBy || ""} onChange={e => setEditForm({ ...editForm, paidBy: e.target.value })} placeholder="שם" style={S.input} />
            <label style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12, cursor: "pointer", fontSize: 13 }}>
              <input type="checkbox" checked={!!editForm.paid} onChange={e => setEditForm({ ...editForm, paid: e.target.checked })} style={{ width: 16, height: 16 }} />
              שולם ✅
            </label>
            <div style={{ display: "flex", gap: 8 }}>
              <button onClick={saveEdit} style={S.btn("#7c3aed")}>שמור</button>
              <button onClick={cancelEdit} style={S.btn("#94a3b8")}>ביטול</button>
            </div>
          </Card>
        ) : (
          <div key={s.id} style={{
            background: "white", borderRadius: 14, padding: "12px 14px", marginBottom: 8,
            boxShadow: "0 2px 10px rgba(0,0,0,0.06)",
            borderRight: `4px solid ${s.paid ? "#059669" : "#e2e8f0"}`,
          }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 700, fontSize: 14, color: "#0f172a" }}>
                  {students.indexOf(s) + 1}. {s.name}
                </div>
                {s.note    && <div style={{ fontSize: 11, color: "#f59e0b", marginTop: 2 }}>📝 {s.note}</div>}
                {s.paidBy  && <div style={{ fontSize: 11, color: "#64748b", marginTop: 2 }}>👤 {s.paidBy}</div>}
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 8, flexShrink: 0 }}>
                {s.paid && <span style={{ fontSize: 12, fontWeight: 700, color: "#059669" }}>₪{s.amount}</span>}
                <button onClick={() => toggle(s.id)} style={{
                  width: 36, height: 36, borderRadius: "50%", border: "none", cursor: "pointer",
                  background: s.paid ? "#dcfce7" : "#fee2e2", fontSize: 18,
                }}>{s.paid ? "✅" : "❌"}</button>
              </div>
            </div>
            <div style={{ display: "flex", gap: 6, marginTop: 8 }}>
              <button onClick={() => startEdit(s)} style={S.smallBtn("#e2e8f0", "#64748b")}>✏️ ערכי</button>
              <button onClick={() => removeStudent(s.id)} style={S.smallBtn("#fee2e2", "#ef4444")}>✕ מחקי</button>
            </div>
          </div>
        )
      ))}

      {showAdd ? (
        <Card>
          <FieldLabel>שם התלמיד/ה *</FieldLabel>
          <input value={newName} onChange={e => setNewName(e.target.value)}
            placeholder="שם התלמיד/ה" style={S.input} autoFocus
            onKeyDown={e => e.key === "Enter" && addStudent()} />
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={addStudent} style={S.btn("#7c3aed")}>הוסיפי</button>
            <button onClick={() => setShowAdd(false)} style={S.btn("#94a3b8")}>ביטול</button>
          </div>
        </Card>
      ) : (
        <button onClick={() => setShowAdd(true)} style={{
          width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
          background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
          cursor: "pointer", fontFamily: "inherit", marginTop: 4,
        }}>+ הוסיפי תלמיד/ה</button>
      )}

      {/* WhatsApp reminder */}
      {students.filter(s => !s.paid).length > 0 && (
        <Card style={{ background: "#f0fdf4", border: "1px solid #bbf7d0", marginTop: 12 }}>
          <div style={{ fontWeight: 700, fontSize: 13, color: "#166534", marginBottom: 6 }}>📱 תזכורת לוואצאפ</div>
          <div style={{ fontSize: 12, color: "#166534", lineHeight: 1.7, userSelect: "all" }}>
            שלום 😊 תזכורת ידידותית לתשלום דמי ועד הורים (₪{feePerStudent}).<br />
            טרם שולם: {students.filter(s => !s.paid).map(s => s.name).join(", ")}.<br />
            ניתן להעביר בפייבוקס / העברה בנקאית. תודה! 🙏
          </div>
        </Card>
      )}
    </div>
  );
}

