function CashTab({ cashLog, setCashLog, students = [], events = [] }) {
  const [showAdd,  setShowAdd]  = useState(false);
  const [addForm,  setAddForm]  = useState(EMPTY_CASH);
  const [editId,   setEditId]   = useState(null);
  const [editForm, setEditForm] = useState({});

  const budgetExpenses        = events
    .filter(ev => (ev.type || "expense") === "expense" && ev.spent > 0)
    .map(ev => ({ id: "budget-" + ev.id, desc: ev.name, amount: -ev.spent, date: ev.date, paidBy: ev.paidBy || "", fromBudget: true }));
  const budgetExpTotal        = budgetExpenses.reduce((s, e) => s + e.amount, 0);

  const cashBalance           = cashLog.reduce((s, c) => s + c.amount, 0);
  const totalIn               = cashLog.filter(c => c.amount > 0).reduce((s, c) => s + c.amount, 0);
  const totalOut              = cashLog.filter(c => c.amount < 0).reduce((s, c) => s + Math.abs(c.amount), 0) + Math.abs(budgetExpTotal);
  const collectedFromStudents = students.reduce((s, st) => s + (st.amount || 0), 0);
  const totalInKupa           = collectedFromStudents + cashBalance + budgetExpTotal;

  // Breakdown by קופה: all amounts (positive + negative) — named collectors + unassigned pool
  const byKupa = {};
  let kupaTotal = 0;
  // Student payments
  students.forEach(s => {
    if ((s.amount || 0) !== 0) {
      if (s.paidBy) { if (!byKupa[s.paidBy]) byKupa[s.paidBy] = 0; byKupa[s.paidBy] += s.amount; }
      else kupaTotal += s.amount;
    }
  });
  // Manual cash log (positive and negative)
  cashLog.forEach(c => {
    if (c.paidBy) { if (!byKupa[c.paidBy]) byKupa[c.paidBy] = 0; byKupa[c.paidBy] += c.amount; }
    else kupaTotal += c.amount;
  });
  // Budget expenses (always negative)
  budgetExpenses.forEach(e => {
    if (e.paidBy) { if (!byKupa[e.paidBy]) byKupa[e.paidBy] = 0; byKupa[e.paidBy] += e.amount; }
    else kupaTotal += e.amount;
  });
  const kupaEntries = Object.entries(byKupa);

  const addEntry = () => {
    if (!addForm.desc.trim() || !addForm.amount) return;
    const amt = Number(addForm.amount) * (addForm.type === "expense" ? -1 : 1);
    setCashLog([...cashLog, { id: Date.now(), ...addForm, amount: amt }]);
    setAddForm(EMPTY_CASH); setShowAdd(false);
  };

  const startEdit  = (e) => { setEditId(e.id); setEditForm({ ...e, amount: String(Math.abs(e.amount)), type: e.amount >= 0 ? "income" : "expense" }); };
  const cancelEdit = () => setEditId(null);
  const saveEdit   = () => {
    const amt = Number(editForm.amount) * (editForm.type === "expense" ? -1 : 1);
    setCashLog(cashLog.map(c => c.id === editId ? { ...editForm, id: editId, amount: amt } : c));
    setEditId(null);
  };
  const removeEntry = (id) => { if (window.confirm("למחוק תנועה זו?")) setCashLog(cashLog.filter(c => c.id !== id)); };

  // running balance
  let running = 0;
  const withBal = cashLog.map(c => { running += c.amount; return { ...c, bal: running }; });

  return (
    <div>
      {/* סה"כ בקופה */}
      <div style={{
        background: "linear-gradient(135deg,#1e293b,#0f172a)",
        borderRadius: 20, padding: 20, color: "white", marginBottom: 12,
      }}>
        <div style={{ opacity: 0.6, fontSize: 13, marginBottom: 2 }}>סה״כ בקופה</div>
        <div style={{ fontSize: 36, fontWeight: 900, letterSpacing: -1 }}>
          {totalInKupa < 0 ? "-" : ""}₪{Math.abs(totalInKupa).toLocaleString()}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 12, marginTop: 14 }}>
          <div>
            <div style={{ opacity: 0.5, fontSize: 10 }}>גבייה</div>
            <div style={{ fontWeight: 700, color: "#4ade80", fontSize: 13 }}>₪{collectedFromStudents.toLocaleString()}</div>
          </div>
          <div>
            <div style={{ opacity: 0.5, fontSize: 10 }}>הכנסות נוספות</div>
            <div style={{ fontWeight: 700, color: "#4ade80", fontSize: 13 }}>+₪{totalIn.toLocaleString()}</div>
          </div>
          <div>
            <div style={{ opacity: 0.5, fontSize: 10 }}>הוצאות</div>
            <div style={{ fontWeight: 700, color: "#f87171", fontSize: 13 }}>-₪{totalOut.toLocaleString()}</div>
          </div>
        </div>
      </div>

      {/* Breakdown by קופה */}
      {(kupaEntries.length > 0 || kupaTotal !== 0) && (
        <Card style={{ background: "#f8fafc", marginBottom: 12 }}>
          <div style={{ fontWeight: 700, fontSize: 13, color: "#1e293b", marginBottom: 8 }}>💼 לפי קופה</div>
          {kupaEntries.map(([name, total]) => (
            <div key={name} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "6px 0", borderBottom: "1px solid #f1f5f9" }}>
              <span style={{ fontSize: 13, fontWeight: 600, color: "#0f172a" }}>👤 {name}</span>
              <span style={{ fontSize: 13, fontWeight: 700, color: total >= 0 ? "#059669" : "#ef4444" }}>{total >= 0 ? "+" : ""}₪{total.toLocaleString()}</span>
            </div>
          ))}
          {kupaTotal !== 0 && (
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "6px 0", borderBottom: "1px solid #f1f5f9" }}>
              <span style={{ fontSize: 13, fontWeight: 600, color: "#0f172a" }}>🏦 קופת איסוף</span>
              <span style={{ fontSize: 13, fontWeight: 700, color: kupaTotal >= 0 ? "#059669" : "#ef4444" }}>{kupaTotal >= 0 ? "+" : ""}₪{kupaTotal.toLocaleString()}</span>
            </div>
          )}
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "8px 0 2px" }}>
            <span style={{ fontSize: 12, fontWeight: 700, color: "#64748b" }}>סה״כ</span>
            <span style={{ fontSize: 13, fontWeight: 900, color: totalInKupa >= 0 ? "#059669" : "#ef4444" }}>{totalInKupa >= 0 ? "+" : ""}₪{totalInKupa.toLocaleString()}</span>
          </div>
        </Card>
      )}

      <h3 style={{ fontWeight: 800, fontSize: 15, color: "#1e293b", marginBottom: 10 }}>יומן תנועות</h3>

      {/* Budget-derived expenses — read-only */}
      {budgetExpenses.length > 0 && (
        <>
          <div style={{ fontSize: 12, fontWeight: 700, color: "#7c3aed", marginBottom: 6, display: "flex", alignItems: "center", gap: 6 }}>
            📊 הוצאות מתקציב
            <span style={{ fontSize: 10, color: "#94a3b8", fontWeight: 400 }}>עריכה רק מלשונית תקציב</span>
          </div>
          {budgetExpenses.map(entry => (
            <div key={entry.id} style={{
              background: "#faf5ff", borderRadius: 12, padding: "12px 14px", marginBottom: 8,
              boxShadow: "0 1px 6px rgba(0,0,0,0.05)", borderRight: "4px solid #a855f7",
            }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 600, fontSize: 14, color: "#0f172a" }}>{entry.desc}</div>
                  <div style={{ fontSize: 11, color: "#94a3b8", marginTop: 2 }}>
                    {entry.date}{entry.paidBy && ` • ${entry.paidBy}`}
                  </div>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 8, flexShrink: 0 }}>
                  <span style={{ background: "#ede9fe", color: "#7c3aed", borderRadius: 6, padding: "2px 7px", fontSize: 10, fontWeight: 700 }}>📊 תקציב</span>
                  <div style={{ fontWeight: 800, fontSize: 15, color: "#ef4444" }}>-₪{Math.abs(entry.amount).toLocaleString()}</div>
                </div>
              </div>
            </div>
          ))}
          {withBal.length > 0 && (
            <div style={{ fontSize: 12, fontWeight: 700, color: "#64748b", marginBottom: 6, marginTop: 12 }}>📝 תנועות ידניות</div>
          )}
        </>
      )}

      {[...withBal].reverse().map(entry => (
        editId === entry.id ? (
          <CashForm key={entry.id} title="✏️ עריכת תנועה" data={editForm} onChange={setEditForm} onSave={saveEdit} onCancel={cancelEdit} />
        ) : (
          <div key={entry.id} style={{
            background: "white", borderRadius: 12, padding: "12px 14px", marginBottom: 8,
            boxShadow: "0 2px 10px rgba(0,0,0,0.06)",
            borderRight: `4px solid ${entry.amount > 0 ? "#4ade80" : "#f87171"}`,
          }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 600, fontSize: 14, color: "#0f172a" }}>{entry.desc}</div>
                <div style={{ fontSize: 11, color: "#94a3b8", marginTop: 2 }}>
                  {entry.date}
                </div>
                {entry.paidBy && <div style={{ fontSize: 11, color: "#64748b", marginTop: 2 }}>👤 {entry.paidBy}</div>}
              </div>
              <div style={{ textAlign: "left", flexShrink: 0 }}>
                <div style={{ fontWeight: 800, fontSize: 15, color: entry.amount > 0 ? "#059669" : "#ef4444" }}>
                  {entry.amount > 0 ? "+" : ""}₪{Math.abs(entry.amount).toLocaleString()}
                </div>
                <div style={{ fontSize: 10, color: "#94a3b8" }}>יתרה ₪{entry.bal.toLocaleString()}</div>
              </div>
            </div>
            <div style={{ display: "flex", gap: 6, marginTop: 8 }}>
              <button onClick={() => startEdit(entry)} style={S.smallBtn("#e2e8f0", "#64748b")}>✏️ ערכי</button>
              <button onClick={() => removeEntry(entry.id)} style={S.smallBtn("#fee2e2", "#ef4444")}>✕ מחקי</button>
            </div>
          </div>
        )
      ))}

      {showAdd ? (
        <CashForm title="➕ תנועה חדשה" data={addForm} onChange={setAddForm} onSave={addEntry} onCancel={() => setShowAdd(false)} />
      ) : (
        <button onClick={() => setShowAdd(true)} style={{
          width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
          background: "transparent", color: "#0f172a", fontWeight: 700, fontSize: 14,
          cursor: "pointer", fontFamily: "inherit", marginTop: 4,
        }}>+ רשמי תנועה</button>
      )}
    </div>
  );
}

