// BUDGET SCREEN — 4-tab layout for a single budget
// ─────────────────────────────────────────
function BudgetScreen({ budget, onUpdate, onBack, activeTab, setActiveTab, gifts, setGifts }) {
  const clr = BUDGET_COLORS[budget.colorKey] || BUDGET_COLORS.purple;

  const setStudents         = (students)  => onUpdate({ students });
  const setEvents           = (events)    => onUpdate({ events });
  const setCashLog          = (cashLog)   => onUpdate({ cashLog });
  const setFeePerStudent    = (val)       => onUpdate({ feePerStudent: val });
  const setExpectedStudents = (val)       => onUpdate({ expectedStudents: val });

  const paidCount             = budget.students.filter(s => s.paid).length;
  const totalBudget           = budget.events.reduce((s, e) => s + e.budget, 0);
  const totalSpent            = budget.events.reduce((s, e) => s + e.spent, 0);
  const cashLogBalance        = budget.cashLog.reduce((s, c) => s + c.amount, 0);
  const collectedFromStudents = budget.students.reduce((s, st) => s + (st.amount || 0), 0);
  const budgetExpensesTotal   = budget.events.filter(ev => (ev.type || "expense") === "expense" && ev.spent > 0).reduce((s, ev) => s + ev.spent, 0);
  const totalInKupa           = collectedFromStudents + cashLogBalance - budgetExpensesTotal;

  return (
    <div style={{ minHeight: "100vh", maxWidth: 480, margin: "0 auto", background: "#f8fafc", fontFamily: "'Heebo', sans-serif", direction: "rtl" }}>
      {/* Header */}
      <div style={{
        background: `linear-gradient(135deg, ${clr.from} 0%, ${clr.to} 100%)`,
        padding: "14px 16px 52px", position: "relative", overflow: "hidden",
      }}>
        <div style={{ position: "absolute", top: -40, left: -20, width: 150, height: 150, borderRadius: "50%", background: "rgba(255,255,255,0.07)" }} />
        <button onClick={onBack} style={{
          background: "rgba(255,255,255,0.2)", border: "none", borderRadius: 10,
          padding: "6px 12px", color: "white", cursor: "pointer", fontFamily: "inherit",
          fontSize: 13, fontWeight: 600, marginBottom: 10, display: "flex", alignItems: "center", gap: 4,
        }}>← כל התקציבים</button>
        <div style={{ color: "white", fontWeight: 900, fontSize: 20, marginBottom: 2 }}>{budget.name}</div>
        <div style={{ color: "rgba(255,255,255,0.75)", fontSize: 13 }}>{budget.className} • {budget.year}</div>
      </div>

      {/* Floating stat cards */}
      <div style={{ display: "flex", gap: 8, padding: "0 14px", marginTop: -34, position: "relative", zIndex: 10, overflowX: "auto", paddingBottom: 4 }}>
        {[
          { icon: "📊", l: "תקציב", v: `₪${totalBudget.toLocaleString()}`, c: clr.from },
          { icon: "✅", l: "שולם",  v: `₪${totalSpent.toLocaleString()}`,  c: "#db2777" },
          { icon: "👧", l: "שילמו", v: budget.students.length > 0 ? `${paidCount}/${budget.students.length}` : "—", c: "#059669" },
          { icon: "💵", l: "מזומן", v: `₪${totalInKupa.toLocaleString()}`,   c: "#ea580c" },
        ].map(s => (
          <div key={s.l} style={{
            background: "white", borderRadius: 14, padding: "10px 10px", minWidth: 82,
            boxShadow: "0 4px 18px rgba(0,0,0,0.12)", flex: "0 0 auto", textAlign: "center",
          }}>
            <div style={{ fontSize: 16 }}>{s.icon}</div>
            <div style={{ fontWeight: 900, fontSize: 13, color: s.c, marginTop: 1 }}>{s.v}</div>
            <div style={{ fontSize: 10, color: "#94a3b8" }}>{s.l}</div>
          </div>
        ))}
      </div>

      {/* Tab content */}
      <div style={{ padding: "14px 14px 90px" }}>
        {activeTab === "budget"  && <BudgetTab  events={budget.events} setEvents={setEvents} collectionBudget={(budget.expectedStudents || 0) * (budget.feePerStudent || 0)} />}
        {activeTab === "collect" && <CollectTab students={budget.students} setStudents={setStudents} feePerStudent={budget.feePerStudent || 500} setFeePerStudent={setFeePerStudent} expectedStudents={budget.expectedStudents || 0} setExpectedStudents={setExpectedStudents} />}
        {activeTab === "gifts"   && <GiftsTab   gifts={gifts}              setGifts={setGifts} />}
        {activeTab === "cash"    && <CashTab     cashLog={budget.cashLog}   setCashLog={setCashLog} students={budget.students} events={budget.events} />}
      </div>

      <BottomNav tabs={BUDGET_TABS} activeTab={activeTab} setActiveTab={setActiveTab} />
    </div>
  );
}

