        <input value={newGLink} onChange={e => setNewGLink(e.target.value)}
          placeholder="קישור לקבוצה (https://chat.whatsapp.com/...)" style={{ ...S.input, marginBottom: 6 }} />
        <button onClick={addGroup} style={{ ...S.btn("#059669"), width: "100%" }}>+ הוסף קבוצה</button>
      </div>

      <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
